function parseMaybeJson(value) {
  if (typeof value !== 'string') return null;
  try { return JSON.parse(value); } catch { return null; }
}

const root = $json || {};
const body = typeof root.body === 'string' ? (parseMaybeJson(root.body) || {}) : (root.body || {});
const d = (body && typeof body === 'object' && Object.keys(body).length > 0) ? body : root;

const pc = d.phase_context || {};
const completedInPhase = pc.completed_in_current_phase ?? 0;
const targetInPhase = pc.target_sessions_in_current_phase ?? 3;
const sessionsRemaining = Math.max(0, targetInPhase - completedInPhase);
const phaseGoal = pc.current_phase?.goal || "Not specified";
const phaseStage = completedInPhase < targetInPhase * 0.4 ? "early" : completedInPhase < targetInPhase * 0.75 ? "middle" : "late";

const systemPrompt = [
  'You are a phase-readiness evaluator for structured therapy progression.',
  'Assess readiness conservatively using phase context, transcript, assessments, mood, and risk signals.',
  '',
  '### PHASE-GOAL AND SESSION BUDGET RULES (CRITICAL)',
  'Current phase goal: "' + phaseGoal + '"',
  'Sessions completed: ' + completedInPhase + ' / ' + targetInPhase + ' (' + sessionsRemaining + ' remaining)',
  'Phase stage: ' + phaseStage,
  '',
  '- readiness_rationale MUST explicitly reference the phase goal and whether the user has demonstrably progressed toward it.',
  '- If phase_stage is "early" or "middle", default to "not_ready" unless there is overwhelming evidence of goal achievement.',
  '- If phase_stage is "late" (final session budget), evaluate whether the goal has been sufficiently addressed:',
  '  - If yes and no major risk: "ready"',
  '  - If partial progress but no risk: "approaching"',
  '  - If insufficient progress or risk present: "not_ready" (this extends the phase)',
  '- session_budget_pressure: with ' + sessionsRemaining + ' session(s) remaining, ' + (sessionsRemaining <= 1 ? 'evaluate readiness more decisively — the user should not stay in this phase indefinitely.' : 'there is still time to deepen work before evaluating transition.'),
  '',
  '### NEXT SESSION HANDOFF GUIDANCE',
  'Include "next_session_handoff" in your output — a 1-2 sentence recommendation for the next therapist session, informed by readiness status, phase goal, and session budget.',
  '',
  'Return ONLY valid JSON.'
].join('\n');

const userPrompt = [
  'PHASE CONTEXT:', JSON.stringify({
    current_phase: pc.current_phase || d.currentPhase || {},
    next_phase: pc.next_phase || null,
    completed_in_current_phase: completedInPhase,
    target_sessions_in_current_phase: targetInPhase,
    sessions_remaining: sessionsRemaining,
    phase_goal: phaseGoal,
    phase_stage: phaseStage,
    recent_case_notes: d.recent_case_notes || [],
    assessments: d.assessments || [],
    mood_entries: d.mood_entries || []
  }),
  '', 'MESSAGES:', JSON.stringify(d.messages || []),
  '', 'TRANSCRIPT:', d.transcript || '',
  '', 'Return JSON schema: {"readiness_for_next_phase":"not_ready | approaching | ready","risk_level":"low | medium | high | critical","requires_escalation":false,"crisis_detected":false,"readiness_rationale":"string","readiness_confidence":0.0,"next_session_handoff":"string","phase_goal_evaluated":true}'
].join('\n');

return [{ json: { systemPrompt, userPrompt } }];

function parseMaybeJson(value) {
  if (typeof value !== 'string') return null;
  try { return JSON.parse(value); } catch { return null; }
}

function pickSource(payload) {
  if (!payload || typeof payload !== 'object') return {};
  if (payload.output && typeof payload.output === 'object') {
    if (payload.output.output && typeof payload.output.output === 'object') return payload.output.output;
    return payload.output;
  }
  const parsedOutput = parseMaybeJson(payload.output);
  if (parsedOutput && typeof parsedOutput === 'object') return parsedOutput;
  if (payload.data && typeof payload.data === 'object') return payload.data;
  return payload;
}

const source = pickSource($json);
return [{
  json: {
    branch: 'readiness',
    model: 'gpt-4o-mini',
    readiness_for_next_phase: source.readiness_for_next_phase || 'not_ready',
    risk_level: source.risk_level || 'low',
    requires_escalation: Boolean(source.requires_escalation),
    crisis_detected: Boolean(source.crisis_detected),
    readiness_rationale: source.readiness_rationale || '',
    readiness_confidence: typeof source.readiness_confidence === 'number' ? source.readiness_confidence : 0.5
  }
}];

